// Patch — Reconstruit PauseFigeeSection dans src/App.jsx pour qu'elle utilise
// le vrai backend (table pause_figee via api.pauses.*) au lieu de agentProfiles
// (stockage local uniquement, jamais synchronisé). Corrige le bug de disparition
// des journées après actualisation. Migration automatique et ponctuelle des
// données locales existantes vers le backend au premier chargement après ce
// patch, pour ne perdre aucune saisie déjà faite. Ajoute aussi : messages de
// chargement/erreur avec bouton Réessayer, boutons plus grands et mieux
// contrastés (mobile + ordinateur), texte clair au lieu du "✕" ambigu, marges
// extérieures alignées sur le bandeau Compteurs.
//
// Usage : node patch_pausefigee_appjsx.js
// À exécuter depuis : C:\Users\olive\Desktop\f2p-pmp
// PRÉREQUIS : avoir déjà exécuté patch_pauses_client_fix.js

const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'src', 'App.jsx');

const OLD_B64 = "";
const NEW_B64 = "";

const oldBlock = Buffer.from(OLD_B64, 'base64').toString('utf-8');
const newBlock = Buffer.from(NEW_B64, 'base64').toString('utf-8');

let content = fs.readFileSync(FILE).toString('utf-8');

const count = content.split(oldBlock).length - 1;
if (count === 0) throw new Error('[PauseFigeeSection] Ancre introuvable dans ' + FILE + ' — le fichier a peut-être déjà changé depuis la préparation de ce patch.');
if (count > 1) throw new Error('[PauseFigeeSection] Ancre trouvée ' + count + ' fois (doit être unique) dans ' + FILE);

content = content.replace(oldBlock, newBlock);

fs.writeFileSync(FILE, content, 'utf-8');
console.log('OK — App.jsx patché (PauseFigeeSection reconstruite sur le vrai backend)');
